use sha2::{Sha256, Digest};

pub const OPERATOR_CONFIG_SEED: &[u8] = b"operator_config";
pub const CUSTOMER_BALANCE_SEED: &[u8] = b"customer_balance";
pub const AGENT_PACKAGE_SEED: &[u8] = b"agent_package";
pub const TASK_RECEIPT_SEED: &[u8] = b"task_receipt";
pub const VAULT_SEED: &[u8] = b"vault";

/// Compute SHA-256 hash of input string for deterministic PDA seed derivation.
pub fn hash_seed(input: &str) -> [u8; 32] { todo!() }

// === Instruction Account Structs (signatures only) ===

#[derive(Accounts)]
pub struct InitializeOperator<'info> {
    #[account(mut)]
    pub authority: Signer<'info>,
    #[account(
        init,
        payer = authority,
        space = 8 + OperatorConfig::INIT_SPACE,
        seeds = [OPERATOR_CONFIG_SEED],
        bump,
    )]
    pub operator_config: Account<'info, OperatorConfig>,
    pub mint: Account<'info, Mint>,
    pub system_program: Program<'info, System>,
}

#[derive(Accounts)]
pub struct CreateCustomerAccount<'info> {
    #[account(mut)]
    pub customer: Signer<'info>,
    #[account(
        init,
        payer = customer,
        space = 8 + CustomerBalance::INIT_SPACE,
        seeds = [CUSTOMER_BALANCE_SEED, customer.key().as_ref()],
        bump,
    )]
    pub customer_balance: Account<'info, CustomerBalance>,
    pub system_program: Program<'info, System>,
}

#[derive(Accounts)]
#[instruction(package_id: String)]
pub struct RegisterAgentPackage<'info> {
    #[account(mut)]
    pub author: Signer<'info>,
    #[account(
        init,
        payer = author,
        space = 8 + AgentPackage::INIT_SPACE,
        seeds = [AGENT_PACKAGE_SEED, &hash_seed(&package_id)],
        bump,
    )]
    pub agent_package: Account<'info, AgentPackage>,
    pub operator_config: Account<'info, OperatorConfig>,
    /// Author's ATA for the configured mint (validated, not created)
    pub author_ata: Account<'info, TokenAccount>,
    pub system_program: Program<'info, System>,
}

#[derive(Accounts)]
pub struct Deposit<'info> {
    #[account(mut)]
    pub customer: Signer<'info>,
    #[account(mut, seeds = [CUSTOMER_BALANCE_SEED, customer.key().as_ref()], bump)]
    pub customer_balance: Account<'info, CustomerBalance>,
    #[account(mut)]
    pub customer_ata: Account<'info, TokenAccount>,
    #[account(mut, seeds = [VAULT_SEED, mint.key().as_ref()], bump)]
    pub vault: Account<'info, TokenAccount>,
    pub operator_config: Account<'info, OperatorConfig>,
    pub mint: Account<'info, Mint>,
    pub token_program: Program<'info, Token>,
}

#[derive(Accounts)]
pub struct Withdraw<'info> {
    #[account(mut)]
    pub customer: Signer<'info>,
    #[account(
        mut,
        seeds = [CUSTOMER_BALANCE_SEED, customer.key().as_ref()],
        bump,
        constraint = customer.key() == customer_balance.customer @ BillingError::Unauthorized,
    )]
    pub customer_balance: Account<'info, CustomerBalance>,
    #[account(mut)]
    pub customer_ata: Account<'info, TokenAccount>,
    #[account(mut, seeds = [VAULT_SEED, mint.key().as_ref()], bump)]
    pub vault: Account<'info, TokenAccount>,
    pub operator_config: Account<'info, OperatorConfig>,
    pub mint: Account<'info, Mint>,
    pub token_program: Program<'info, Token>,
}

