/// Settle a task with three-case quality-gated payment splitting.
///
/// Case 1: No agent package — full amount to treasury.
/// Case 2: Agent package + quality_met=true — split between author and treasury.
/// Case 3: Agent package + quality_met=false — zero charge, no transfers.
///
/// Validates: not paused, operator authorized, per-task cap, daily cap (with day rollover), sufficient balance.
pub fn settle_task(
    ctx: Context<SettleTask>,
    task_id: String,
    amount: u64,
    receipt_hash: [u8; 32],
    quality_met: bool,
) -> Result<()> { todo!() }

#[derive(Accounts)]
#[instruction(task_id: String)]
pub struct SettleTask<'info> {
    #[account(mut)]
    pub operator: Signer<'info>,
    #[account(seeds = [OPERATOR_CONFIG_SEED], bump)]
    pub operator_config: Account<'info, OperatorConfig>,
    #[account(mut)]
    pub customer_balance: Account<'info, CustomerBalance>,
    #[account(mut)]
    pub treasury_ata: Account<'info, TokenAccount>,
    #[account(mut, seeds = [VAULT_SEED, mint.key().as_ref()], bump)]
    pub vault: Account<'info, TokenAccount>,
    /// CHECK: PDA authority for vault signing
    pub vault_authority: UncheckedAccount<'info>,
    #[account(
        init,
        payer = operator,
        space = 8 + TaskReceipt::INIT_SPACE,
        seeds = [TASK_RECEIPT_SEED, &hash_seed(&task_id)],
        bump,
    )]
    pub task_receipt: Account<'info, TaskReceipt>,
    pub mint: Account<'info, Mint>,
    pub token_program: Program<'info, Token>,
    pub system_program: Program<'info, System>,
    pub clock: Sysvar<'info, Clock>,
    // Optional accounts for agent package settlement
    pub agent_package: Option<Account<'info, AgentPackage>>,
    #[account(mut)]
    pub author_ata: Option<Account<'info, TokenAccount>>,
}

